## 4.1 Redis Cache Service

### 4.1 Redis Cache Service

**File:** `apps/web/lib/services/cache.ts`

```typescript
import { Redis } from 'ioredis'

let redis: Redis | null = null

function getRedis(): Redis {
  if (!redis) {
    const url = process.env.REDIS_URL
    if (!url) throw new Error('REDIS_URL not configured')
    redis = new Redis(url)
  }
  return redis
}

// ============================================
// MERGED DOCS CACHE
// ============================================

interface CachedMergedDocs {
  docs: Array<{
    id: string
    title: string
    content: string
    category: string
    tokenCount: number
    source: 'project' | 'shared'
    collectionName?: string
  }>
  version: string
  cachedAt: number
}

const MERGED_DOCS_TTL = 3600 // 1 hour

export async function getCachedMergedDocs(
  projectId: string,
  versionHash: string
): Promise<CachedMergedDocs | null> {
  const key = `merged:${projectId}:${versionHash}`
  const cached = await getRedis().get(key)

  if (!cached) return null

  return JSON.parse(cached)
}

export async function setCachedMergedDocs(
  projectId: string,
  versionHash: string,
  docs: CachedMergedDocs
): Promise<void> {
  const key = `merged:${projectId}:${versionHash}`
  await getRedis().setex(key, MERGED_DOCS_TTL, JSON.stringify(docs))
}

export async function invalidateMergedDocsCache(projectId: string): Promise<void> {
  const pattern = `merged:${projectId}:*`
  const keys = await getRedis().keys(pattern)
  if (keys.length > 0) {
    await getRedis().del(...keys)
  }
}

// ============================================
// QUERY CACHE
// ============================================

interface CachedQueryResult {
  sections: Array<{
    title: string
    content: string
    relevanceScore: number
    tokenCount: number
  }>
  totalTokens: number
  cachedAt: number
}

const QUERY_CACHE_TTL = 300 // 5 minutes

export async function getCachedQueryResult(
  projectId: string,
  queryHash: string
): Promise<CachedQueryResult | null> {
  const key = `query:${projectId}:${queryHash}`
  const cached = await getRedis().get(key)

  if (!cached) return null

  return JSON.parse(cached)
}

export async function setCachedQueryResult(
  projectId: string,
  queryHash: string,
  result: CachedQueryResult
): Promise<void> {
  const key = `query:${projectId}:${queryHash}`
  await getRedis().setex(key, QUERY_CACHE_TTL, JSON.stringify(result))
}

export async function invalidateQueryCache(projectId: string): Promise<void> {
  const pattern = `query:${projectId}:*`
  const keys = await getRedis().keys(pattern)
  if (keys.length > 0) {
    await getRedis().del(...keys)
  }
}

// ============================================
// CACHE INVALIDATION TRIGGERS
// ============================================

export async function onCollectionUpdated(collectionId: string): Promise<void> {
  // Find all projects using this collection
  const { prisma } = await import('@/lib/prisma')

  const links = await prisma.projectSharedContext.findMany({
    where: { collectionId },
    select: { projectId: true }
  })

  // Invalidate caches for all affected projects
  await Promise.all(
    links.map(link => Promise.all([
      invalidateMergedDocsCache(link.projectId),
      invalidateQueryCache(link.projectId)
    ]))
  )
}

export async function onProjectLinksChanged(projectId: string): Promise<void> {
  await Promise.all([
    invalidateMergedDocsCache(projectId),
    invalidateQueryCache(projectId)
  ])
}
```


